mapper.select:
select ts.id, ts.create_by, ts.update_by, ts.create_time, ts.update_time, ts.delete_flag, ts.software_code,
ts.software_name, ts.project_code, tps.project_name, ts.status, ts.description, ts.note, ts.cost_type, ts.money
from t_software ts left join t_project_statis tps on ts.project_code = tps.project_code


        EXISTS (
        SELECT 1 FROM t_software_process tsp  WHERE  ts.id = tsp.software_id
            and tsp.delete_flag = '0' and ( tsp.create_by = #{createBy} OR  tsp.handle_by = #{createBy})
        )
        AND ts.delete_flag = '0'

     and ts.id = #{id}
     AND ts.software_code like concat('%', #{softwareCode}, '%')
     AND ts.software_name like concat('%', #{softwareName}, '%')
     AND ts.project_code like concat('%', #{projectCode}, '%')
     AND ts.cost_type = #{costType}
     AND ts.money = #{money}
     AND ts.description like concat('%', #{description}, '%')
     AND ts.status = #{status}
     AND ts.create_time >= #{params.beginTime}
     AND ts.create_time <= #{params.endTime}

mapper.update:
update t_software
software_code = #{softwareCode}, software_name = #{softwareName}, project_code = #{projectCode}, description = #{description}, update_by = #{updateBy}, money = #{money}, cost_type = #{costType}, status = #{status}, update_time = sysdate()
where id = #{id}

